"""
Parameterized generator for GH434_napari_8098.

Source PR:    https://github.com/napari/napari/pull/8098
Source Issue: https://github.com/napari/napari/issues/7962

Seed varies: renames 'added' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH434_napari_8098'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH434_napari_8098'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('added', 'added' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH434_napari_8098',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'napari/napari',
                "pr_number": 8098,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/napari/napari/pull/8098",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'src/napari/layers/_layer_actions.py': '"""This module contains actions (functions) that operate on layers.\nAmong other potential uses, these will populate the menu when you right-click\non a layer in the LayerList.\n"""\n\nfrom __future__ import annotations\n\nimport warnings\nfrom typing import TYPE_CHECKING, cast\n\nimport numpy as np\nimport numpy.typing as npt\n\nfrom napari import layers\nfrom napari.layers import Image, Labels, Layer\nfrom napari.layers._source import layer_source\nfrom napari.layers.utils import stack_utils\nfrom napari.layers.utils._link_layers import get_linked_layers\nfrom napari.utils.translations import trans\n\nif TYPE_CHECKING:\n    from napari.components import LayerList\n\n\ndef _duplicate_layer(ll: LayerList, *, name: str = \'\') -> None:\n    from copy import deepcopy\n\n    for lay in list(ll.selection):\n        data, state, type_str = lay.as_layer_data_tuple()\n        state[\'name\'] = trans._(\'{name} copy\', name=lay.name)\n        with layer_source(parent=lay):\n            new = Layer.create(deepcopy(data), state, type_str)\n        ll.insert(ll.index(lay) + 1, new)\n\n\ndef _split_stack(ll: LayerList, axis: int = 0) -> None:\n    layer = ll.selection.active\n    if not isinstance(layer, Image):\n        return\n    if layer.rgb:\n        # determine if image is rgb (3 channel) or rbga (4 channel)\n        with_alpha = False\n        if layer.data.shape[-1] == 4:\n            # set with_alpha option true for rgba image\n            with_alpha = True\n        images = stack_utils.split_rgb(layer, with_alpha=with_alpha)\n    else:\n        images = stack_utils.stack_to_images(layer, axis)\n    ll.remove(layer)\n    ll.extend(images)\n    ll.selection = set(images)  # type: ignore\n\n\ndef _split_rgb(ll: LayerList) -> None:\n    return _split_stack(ll)\n\n\ndef _convert(ll: LayerList, type_: str) -> None:\n    from napari.layers import Shapes\n\n    for lay in list(ll.selection):\n        idx = ll.index(lay)\n        if isinstance(lay, Shapes) and type_ == \'labels\':\n            data = lay.to_labels()\n            idx += 1\n        elif (\n            not np.issubdtype(lay.data.dtype, np.integer) and type_ == \'labels\'\n        ):\n            data = lay.data.astype(int)\n            idx += 1\n        else:\n            data = lay.data\n            # int image layer to labels is fully reversible\n            ll.pop(idx)\n        # projection mode may not be compatible with new type,\n        # we\'re ok with dropping it in that case\n        layer_type = getattr(layers, type_.title())\n        state = lay._get_base_state()\n        try:\n            layer_type._projectionclass(state[\'projection_mode\'].value)\n        except ValueError:\n            state[\'projection_mode\'] = \'none\'\n            warnings.warn(\n                trans._(\n                    \'projection mode "{mode}" is not compatible with {type_} layers. Falling back to "none".\',\n                    mode=state[\'projection_mode\'],\n                    type_=type_.title(),\n                    deferred=True,\n                ),\n                category=UserWarning,\n                stacklevel=1,\n            )\n        new_layer = Layer.create(data, state, type_)\n        ll.insert(idx, new_layer)\n\n\n# TODO: currently, we have to create a thin _convert_to_x wrapper around _convert\n# here for the purpose of type hinting (which partial doesn\'t do) ...\n# so that inject_dependencies works correctly.\n# however, we could conceivably add an `args` option to register_action\n# that would allow us to pass additional arguments, like a partial.\ndef _convert_to_labels(ll: LayerList) -> None:\n    return _convert(ll, \'labels\')\n\n\ndef _convert_to_image(ll: LayerList) -> None:\n    return _convert(ll, \'image\')\n\n\ndef _merge_stack(ll: LayerList, rgb: bool = False) -> None:\n    # force selection to follow LayerList ordering\n    imgs = cast(list[Image], [layer for layer in ll if layer in ll.selection])\n    merged = (\n        stack_utils.merge_rgb(imgs)\n        if rgb\n        else stack_utils.images_to_stack(imgs)\n    )\n    for layer in imgs:\n        ll.remove(layer)\n    ll.append(merged)\n\n\ndef _toggle_visibility(ll: LayerList) -> None:\n    current_visibility_state = []\n    for layer in ll.selection:\n        current_visibility_state.append(layer.visible)\n\n    for visibility, layer in zip(\n        current_visibility_state, ll.selection, strict=False\n    ):\n        if layer.visible == visibility:\n            layer.visible = not visibility\n\n\ndef _show_selected(ll: LayerList) -> None:\n    for lay in ll.selection:\n        lay.visible = True\n\n\ndef _hide_selected(ll: LayerList) -> None:\n    for lay in ll.selection:\n        lay.visible = False\n\n\ndef _show_unselected(ll: LayerList) -> None:\n    for lay in ll:\n        if lay not in ll.selection:\n            lay.visible = True\n\n\ndef _hide_unselected(ll: LayerList) -> None:\n    for lay in ll:\n        if lay not in ll.selection:\n            lay.visible = False\n\n\ndef _link_selected_layers(ll: LayerList) -> None:\n    ll.link_layers(ll.selection)\n\n\ndef _unlink_selected_layers(ll: LayerList) -> None:\n    ll.unlink_layers(ll.selection)\n\n\ndef _select_linked_layers(ll: LayerList) -> None:\n    linked_layers_in_list = [\n        x for x in get_linked_layers(*ll.selection) if x in ll\n    ]\n    ll.selection.update(linked_layers_in_list)\n\n\ndef _convert_dtype(ll: LayerList, mode: npt.DTypeLike = \'int64\') -> None:\n    if not (layer := ll.selection.active):\n        return\n\n    if not isinstance(layer, Labels):\n        raise NotImplementedError(\n            trans._(\n                \'Data type conversion only implemented for labels\',\n                deferred=True,\n            )\n        )\n\n    target_dtype = np.dtype(mode)\n    if (\n        np.min(layer.data) < np.iinfo(target_dtype).min\n        or np.max(layer.data) > np.iinfo(target_dtype).max\n    ):\n        raise AssertionError(\n            trans._(\n                \'Labeling contains values outside of the target data type range.\',\n                deferred=True,\n            )\n        )\n\n    layer.data = layer.data.astype(np.dtype(mode))\n\n\ndef _project(ll: LayerList, axis: int = 0, mode: str = \'max\') -> None:\n    layer = ll.selection.active\n    if not layer:\n        return\n    if not isinstance(layer, Image):\n        raise NotImplementedError(\n            trans._(\n                \'Projections are only implemented for images\', deferred=True\n            )\n        )\n\n    # this is not the desired behavior for coordinate-based layers\n    # but the action is currently only enabled for \'image_active and ndim > 2\'\n    # before opening up to other layer types, this line should be updated.\n    data = (getattr(np, mode)(layer.data, axis=axis, keepdims=False),)\n\n    # Get the meta-data of the layer, but without transforms,\n    # the transforms are updated bellow as projection of transforms\n    # requires a bit more work than just copying them\n    # (e.g., the axis of the projection should be removed).\n    # It is done in `set_slice` method of `TransformChain`\n    meta = {\n        key: layer._get_base_state()[key]\n        for key in layer._get_base_state()\n        if key\n        not in (\n            \'scale\',\n            \'translate\',\n            \'rotate\',\n            \'shear\',\n            \'affine\',\n            \'axis_labels\',\n            \'units\',\n        )\n    }\n    meta.update(  # sourcery skip\n        {\n            \'name\': f\'{layer} {mode}-proj\',\n            \'colormap\': layer.colormap.name,\n            \'rendering\': layer.rendering,\n        }\n    )\n    new = Layer.create(data, meta, layer._type_string)\n    # add transforms from original layer, but drop the axis of the projection\n    new._transforms = layer._transforms.set_slice(\n        [ax for ax in range(layer.ndim) if ax != axis]\n    )\n\n    ll.append(new)\n',
            'src/napari/layers/_tests/test_layer_actions.py': 'import numpy as np\nimport pint\nimport pytest\nimport zarr\n\nfrom napari.components.layerlist import LayerList\nfrom napari.layers import Image, Labels, Points, Shapes\nfrom napari.layers._layer_actions import (\n    _convert,\n    _convert_dtype,\n    _duplicate_layer,\n    _hide_selected,\n    _hide_unselected,\n    _link_selected_layers,\n    _merge_stack,\n    _project,\n    _show_selected,\n    _show_unselected,\n    _split_rgb,\n    _split_stack,\n    _toggle_visibility,\n)\n\nREG = pint.get_application_registry()\n\n\ndef test_split_stack():\n    layer_list = LayerList()\n    layer_list.append(Image(np.random.rand(8, 8, 8)))\n    assert len(layer_list) == 1\n\n    layer_list.selection.active = layer_list[0]\n    _split_stack(layer_list)\n    assert len(layer_list) == 8\n\n    for idx in range(8):\n        assert layer_list[idx].data.shape == (8, 8)\n\n\ndef test_split_rgb():\n    layer_list = LayerList()\n    layer_list.append(Image(np.random.random((48, 48, 3))))\n    assert len(layer_list) == 1\n    assert layer_list[0].rgb is True\n\n    layer_list.selection.active = layer_list[0]\n    _split_rgb(layer_list)\n    assert len(layer_list) == 3\n\n    for idx in range(3):\n        assert layer_list[idx].data.shape == (48, 48)\n\n\ndef test_merge_stack():\n    layer_list = LayerList()\n    layer_list.append(Image(np.random.rand(8, 8)))\n    layer_list.append(Image(np.random.rand(8, 8)))\n    assert len(layer_list) == 2\n\n    layer_list.selection.active = layer_list[0]\n    layer_list.selection.add(layer_list[1])\n    _merge_stack(layer_list)\n    assert len(layer_list) == 1\n    assert layer_list[0].data.shape == (2, 8, 8)\n\n\ndef test_merge_stack_rgb():\n    layer_list = LayerList()\n    layer_list.append(Image(np.random.rand(8, 8)))\n    layer_list.append(Image(np.random.rand(8, 8)))\n    layer_list.append(Image(np.random.rand(8, 8)))\n    assert len(layer_list) == 3\n\n    layer_list.selection.active = layer_list[0]\n    layer_list.selection.add(layer_list[1])\n    layer_list.selection.add(layer_list[2])\n\n    # check that without R G B colormaps we warn\n    with pytest.raises(ValueError, match=\'Missing colormap\'):\n        _merge_stack(layer_list, rgb=True)\n\n    layer_list[0].colormap = \'red\'\n    layer_list[1].colormap = \'green\'\n    layer_list[2].colormap = \'blue\'\n    _merge_stack(layer_list, rgb=True)\n    assert len(layer_list) == 1\n    assert layer_list[0].data.shape == (8, 8, 3)\n    assert layer_list[0].rgb is True\n\n\ndef test_toggle_visibility():\n    """Test toggling visibility of a layer."""\n    layer_list = LayerList()\n    layer_list.append(Points([[0, 0]]))\n    layer_list[0].visible = False\n\n    layer_list.selection.active = layer_list[0]\n    _toggle_visibility(layer_list)\n\n    assert layer_list[0].visible is True\n\n\ndef test_toggle_visibility_with_linked_layers():\n    """Test toggling visibility of a layer."""\n    layer_list = LayerList()\n    layer_list.append(Points([[0, 0]]))\n    layer_list.append(Points([[0, 0]]))\n    layer_list.append(Points([[0, 0]]))\n    layer_list.append(Points([[0, 0]]))\n\n    layer_list.selection.active = layer_list[0]\n    layer_list.selection.add(layer_list[1])\n    layer_list.selection.add(layer_list[2])\n\n    _link_selected_layers(layer_list)\n\n    layer_list[3].visible = False\n\n    layer_list.selection.remove(layer_list[0])\n    layer_list.selection.add(layer_list[3])\n\n    _toggle_visibility(layer_list)\n\n    assert layer_list[0].visible is False\n    assert layer_list[1].visible is False\n    assert layer_list[2].visible is False\n    assert layer_list[3].visible is True\n\n\n@pytest.mark.parametrize(\'layer_type\', [Points, Shapes])\ndef test_duplicate_layers(layer_type):\n    def _dummy():\n        pass\n\n    layer_list = LayerList()\n    layer_list.append(layer_type([], name=\'test\'))\n    layer_list.selection.active = layer_list[0]\n    layer_list[0].events.data.connect(_dummy)\n    assert len(layer_list[0].events.data.callbacks) == 2\n    assert len(layer_list) == 1\n    _duplicate_layer(layer_list)\n    assert len(layer_list) == 2\n    assert layer_list[0].name == \'test\'\n    assert layer_list[1].name == \'test copy\'\n    assert layer_list[1].events.source is layer_list[1]\n    assert (\n        len(layer_list[1].events.data.callbacks) == 1\n    )  # `events` Event Emitter\n    assert layer_list[1].source.parent() is layer_list[0]\n\n\ndef test_hide_unselected_layers():\n    layer_list = make_three_layer_layerlist()\n    layer_list[0].visible = True\n    layer_list[1].visible = True\n    layer_list[2].visible = True\n\n    layer_list.selection.active = layer_list[1]\n\n    assert layer_list[0].visible is True\n    assert layer_list[1].visible is True\n    assert layer_list[2].visible is True\n\n    _hide_unselected(layer_list)\n\n    assert layer_list[0].visible is False\n    assert layer_list[1].visible is True\n    assert layer_list[2].visible is False\n\n\ndef test_show_unselected_layers():\n    layer_list = make_three_layer_layerlist()\n    layer_list[0].visible = False\n    layer_list[1].visible = True\n    layer_list[2].visible = True\n\n    layer_list.selection.active = layer_list[1]\n\n    assert layer_list[0].visible is False\n    assert layer_list[1].visible is True\n    assert layer_list[2].visible is True\n\n    _show_unselected(layer_list)\n\n    assert layer_list[0].visible is True\n    assert layer_list[1].visible is True\n    assert layer_list[2].visible is True\n\n\ndef test_hide_selected_layers():\n    layer_list = make_three_layer_layerlist()\n    layer_list[0].visible = False\n    layer_list[1].visible = True\n    layer_list[2].visible = True\n\n    layer_list.selection.active = layer_list[0]\n    layer_list.selection.add(layer_list[1])\n\n    assert layer_list[0].visible is False\n    assert layer_list[1].visible is True\n    assert layer_list[2].visible is True\n\n    _hide_selected(layer_list)\n\n    assert layer_list[0].visible is False\n    assert layer_list[1].visible is False\n    assert layer_list[2].visible is True\n\n\ndef test_show_selected_layers():\n    layer_list = make_three_layer_layerlist()\n    layer_list[0].visible = False\n    layer_list[1].visible = True\n    layer_list[2].visible = True\n\n    layer_list.selection.active = layer_list[0]\n    layer_list.selection.add(layer_list[1])\n\n    assert layer_list[0].visible is False\n    assert layer_list[1].visible is True\n    assert layer_list[2].visible is True\n\n    _show_selected(layer_list)\n\n    assert layer_list[0].visible is True\n    assert layer_list[1].visible is True\n    assert layer_list[2].visible is True\n\n\n@pytest.mark.parametrize(\n    \'mode\', [\'max\', \'min\', \'std\', \'sum\', \'mean\', \'median\']\n)\ndef test_projections(mode):\n    ll = LayerList()\n    ll.append(\n        Image(\n            np.random.rand(7, 8, 8),\n            scale=(3, 2, 2),\n            translate=(10, 5, 5),\n            units=(\'nm\', \'um\', \'um\'),\n            axis_labels=(\'z\', \'y\', \'x\'),\n        )\n    )\n    assert len(ll) == 1\n    assert ll[-1].data.ndim == 3\n    _project(ll, mode=mode)\n    assert len(ll) == 2\n    # because keepdims = False\n    assert ll[-1].data.shape == (8, 8)\n    assert tuple(ll[-1].scale) == (2, 2)\n    assert tuple(ll[-1].translate) == (5, 5)\n    assert ll[-1].units == (REG.um, REG.um)\n    assert ll[-1].axis_labels == (\'y\', \'x\')\n\n\n@pytest.mark.parametrize(\n    \'mode\',\n    [\'int8\', \'int16\', \'int32\', \'int64\', \'uint8\', \'uint16\', \'uint32\', \'uint64\'],\n)\ndef test_convert_dtype(mode):\n    ll = LayerList()\n    data = np.zeros((10, 10), dtype=np.int16)\n    ll.append(Labels(data))\n    assert ll[-1].data.dtype == np.int16\n\n    data[5, 5] = 1000\n    assert data[5, 5] == 1000\n    if mode == \'int8\' or mode == \'uint8\':\n        # label value 1000 is outside of the target data type range.\n        with pytest.raises(AssertionError):\n            _convert_dtype(ll, mode=mode)\n        assert ll[-1].data.dtype == np.int16\n    else:\n        _convert_dtype(ll, mode=mode)\n        assert ll[-1].data.dtype == np.dtype(mode)\n\n    assert ll[-1].data[5, 5] == 1000\n    assert ll[-1].data.flatten().sum() == 1000\n\n\n@pytest.mark.filterwarnings(\'ignore:projection mode :UserWarning\')\n@pytest.mark.parametrize(\n    (\'layer\', \'type_\'),\n    [\n        (Image(np.random.rand(10, 10)), \'labels\'),\n        (Image(np.array([[1.5, 2.5], [3.5, 4.5]])), \'labels\'),\n        (Image(np.array([[1, 2], [3, 4]], dtype=(int))), \'labels\'),\n        (\n            Image(zarr.array([[1, 2], [3, 4]], dtype=(int), chunks=(1, 2))),\n            \'labels\',\n        ),\n        (Labels(np.ones((10, 10), dtype=int)), \'image\'),\n        (Shapes([np.array([[0, 0], [0, 10], [10, 0], [10, 10]])]), \'labels\'),\n    ],\n)\ndef test_convert_layer(layer, type_):\n    ll = LayerList()\n    layer.scale *= 1.5\n    original_scale = layer.scale.copy()\n    ll.append(layer)\n    assert ll[0]._type_string != type_\n    _convert(ll, \'labels\')\n    if isinstance(layer, Shapes) or (\n        type_ == \'labels\'\n        and isinstance(layer, Image)\n        and np.issubdtype(layer.data.dtype, float)\n    ):\n        assert ll[1]._type_string == type_\n        assert np.array_equal(ll[1].scale, original_scale)\n    else:\n        assert (\n            layer.data is ll[0].data\n        )  # check array data not copied unnecessarily\n\n\ndef test_convert_warns_with_projecton_mode():\n    # inplace\n    ll = LayerList(\n        [Image(np.random.rand(10, 10).astype(int), projection_mode=\'mean\')]\n    )\n    with pytest.warns(UserWarning, match=\'projection mode\'):\n        _convert(ll, \'labels\')\n    assert isinstance(ll[\'Image\'], Labels)\n    # not inplace\n    ll = LayerList([Image(np.random.rand(10, 10), projection_mode=\'mean\')])\n    with pytest.warns(UserWarning, match=\'projection mode\'):\n        _convert(ll, \'labels\')\n    assert isinstance(ll[\'Image [1]\'], Labels)\n\n\ndef make_three_layer_layerlist():\n    layer_list = LayerList()\n    layer_list.append(Points([[0, 0]], name=\'test\'))\n    layer_list.append(Image(np.random.rand(8, 8, 8)))\n    layer_list.append(Image(np.random.rand(8, 8, 8)))\n\n    return layer_list\n',
        }
